I've been using the following generic variant caster. I mainly wrote it for my own use with `mapbox::variant`, but the variant type comes in as a template parameter and `boost::variant` has the same interface, so you should be able to use it mostly as is.

```c++
namespace pybind11 { namespace detail {

// Can be replaced by a generic lambda in C++14
struct variant_caster_visitor {
    return_value_policy policy;
    handle parent;

    template<class T>
    handle operator()(T const& src) const {
        return make_caster<T>::cast(src, policy, parent);
    }
};

template<class Variant> struct variant_caster;

template<template<class...> class V, class... Ts>
struct variant_caster<V<Ts...>> {
    using Type = V<Ts...>;

    template<class T>
    bool try_load(handle src, bool convert) {
        auto caster = make_caster<T>();
        if (caster.load(src, convert)) {
            value = cast_op<T>(caster);
            return true;
        }
        return false;
    }

    bool load(handle src, bool convert) {
        auto loaded = {false, try_load<Ts>(src, convert)...};
        return std::any_of(loaded.begin(), loaded.end(), [](bool b) { return b; });
    }

    static handle cast(Type const& src, return_value_policy policy, handle parent) {
        // If you see an error here, add `boost::` qualifier to `apply_visitor`
        return apply_visitor(variant_caster_visitor{policy, parent}, src);
    }

    PYBIND11_TYPE_CASTER(Type, _("Variant"));
};

// Add specialization for concrete variant type
template<class... Args> struct type_caster<boost::variant<Args...>>
    : variant_caster<boost::variant<Args...>> {};

}} // namespace pybind11::detail
```

Some notes:

* This works quite well for me, but it has not been extensively tested.
* Should work with any variant as long as its types are exposed to Python via `py::class_` or have their own type casters. But recursive variants are not covered (`recursive_wrapper<T>`).
* It converts to/from any type on both sides.

@SwartzCr Thanks for link. Seen that already. Got it sorted with Nginx server instead. Shiny open source does not support SSL unless you are using the Pro version.

So using Nginx is a hack - by redirecting a port to Shiny's, eg:

```
server {
        listen 8888 ssl;
        server_name xxx.co.uk www.xxx.co.uk;

        ssl_certificate /etc/letsencrypt/live/xxx.co.uk/fullchain.pem;
        ssl_certificate_key /etc/letsencrypt/live/xxx.co.uk/privkey.pem;

        location ~ /.well-known {
            allow all;
        }

        location / {
                proxy_set_header   X-Real-IP $remote_addr;
                proxy_set_header   Host      $http_host;
                proxy_pass         http://127.0.0.1:3838;
        }

    }
```

